async (params, browser) => {
  // Open Jira issue
  await browser.open(`${params.jira_url}/browse/${params.issue_key}`)

  // Let page load
  await browser.wait(2000)

  // Transition issue via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const target = params.target_status.toLowerCase(); const tResp = await fetch(baseUrl + '/rest/api/3/issue/' + params.issue_key + '/transitions', { credentials: 'same-origin' }); if (!tResp.ok) throw new Error('Failed to get transitions: ' + tResp.status); const tData = await tResp.json(); const transitions = tData.transitions || []; const match = transitions.find(t => t.name.toLowerCase() === target || t.to.name.toLowerCase() === target); if (!match) return { success: false, message: 'Status not available', available_transitions: transitions.map(t => ({ id: t.id, name: t.name, to: t.to.name })) }; const resp = await fetch(baseUrl + '/rest/api/3/issue/' + params.issue_key + '/transitions', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify({ transition: { id: match.id } }) }); if (!resp.ok) throw new Error('Transition failed: ' + resp.status); return { success: true, key: '' + params.issue_key + '', transitioned_to: match.to.name }`)

  return result
}
